// Archivo: intermedio_parte1.js (PARTE 1: Preguntas 1 a 90)
export const preguntasNivel2_Parte1 = [
  { id: 1, curso: "Red Hat System Administration I", pregunta: "¿Cómo verificarías qué proceso está usando un puerto específico?", opciones: ["netstat -rn", "ss -tuln | grep <puerto> o lsof -i :<puerto>", "ps aux | grep puerto", "top -p puerto", "ifconfig puerto"], respuestaCorrecta: 1, explicacion: "Los comandos ss (socket statistics) o lsof (list open files) permiten identificar qué proceso tiene abierto un puerto específico en el sistema." },
  { id: 2, curso: "Red Hat System Administration I", pregunta: "¿Cómo encontrarías archivos modificados en las últimas 24 horas?", opciones: ["find / -mtime -1", "ls -lt /", "grep -r '24h' /", "locate -time 24", "find / -newer 24h"], respuestaCorrecta: 0, explicacion: "El comando find con el parámetro -mtime -1 busca archivos modificados en las últimas 24 horas (1 día)." },
  { id: 3, curso: "Red Hat System Administration I", pregunta: "¿Qué diferencia existe entre permisos simbólicos y numéricos en chmod?", opciones: ["No hay diferencia, son lo mismo.", "Los simbólicos usan letras (rwx) y los numéricos usan dígitos (755).", "Los numéricos son más seguros que los simbólicos.", "Los simbólicos solo funcionan con root.", "Los numéricos no permiten permisos recursivos."], respuestaCorrecta: 1, explicacion: "Los permisos simbólicos usan notación con letras como u+rwx, mientras que los numéricos usan valores octales como 755 para representar los mismos permisos." },
  { id: 4, curso: "Red Hat System Administration I", pregunta: "¿Cómo aplicarías permisos recursivos a una carpeta y su contenido?", opciones: ["chmod -R 755 carpeta", "chmod --all 755 carpeta", "chmod -recursive 755 carpeta", "chmod 755 carpeta/*", "chmod -r 755 carpeta"], respuestaCorrecta: 0, explicacion: "La opción -R (recursivo) aplica los permisos a la carpeta y a todos sus archivos y subdirectorios." },
  { id: 5, curso: "Red Hat System Administration I", pregunta: "¿Qué hace umask y cómo afecta a los archivos nuevos?", opciones: ["Define los permisos máximos que tendrán los archivos nuevos.", "Crea máscaras de red.", "Bloquea archivos del sistema.", "Cambia el propietario de archivos nuevos.", "Comprime archivos automáticamente."], respuestaCorrecta: 0, explicacion: "umask establece una máscara que determina qué permisos NO tendrán los archivos y directorios creados por defecto, afectando los permisos iniciales." },
  { id: 6, curso: "Red Hat System Administration I", pregunta: "¿Cómo mostrarías las últimas entradas de un log del sistema en tiempo real?", opciones: ["cat /var/log/syslog", "tail -f /var/log/messages", "head /var/log/syslog", "grep real /var/log/*", "less /var/log/messages"], respuestaCorrecta: 1, explicacion: "tail -f muestra las últimas líneas de un archivo y se mantiene actualizando en tiempo real a medida que se añaden nuevas entradas." },
  { id: 7, curso: "Red Hat System Administration I", pregunta: "¿Qué comando usarías para filtrar errores dentro de un archivo de log?", opciones: ["find error /var/log/syslog", "grep -i 'error' /var/log/syslog", "cat error /var/log/syslog", "locate error", "search error /var/log/syslog"], respuestaCorrecta: 1, explicacion: "grep busca patrones de texto en archivos. La opción -i hace la búsqueda insensible a mayúsculas/minúsculas." },
  { id: 8, curso: "Red Hat System Administration I", pregunta: "¿Cómo reiniciarías red en un sistema Red Hat usando herramientas modernas?", opciones: ["service network restart", "systemctl restart NetworkManager", "ifconfig restart", "net restart", "ip restart all"], respuestaCorrecta: 1, explicacion: "En sistemas modernos Red Hat, NetworkManager es el servicio que gestiona la red, y se reinicia con systemctl." },
  { id: 9, curso: "Red Hat System Administration I", pregunta: "¿Cómo identificarías si un servicio falló al arrancar?", opciones: ["systemctl status <servicio>", "ps aux | grep fallido", "top -failed", "service --check", "netstat -failed"], respuestaCorrecta: 0, explicacion: "systemctl status muestra el estado actual del servicio, incluyendo si falló al iniciar y los mensajes de error asociados." },
  { id: 10, curso: "Red Hat System Administration I", pregunta: "¿Qué información útil da systemctl status?", opciones: ["Solo el PID del proceso.", "Estado activo/inactivo, si está habilitado, PID, memoria usada y últimas líneas del log.", "Solo la versión del servicio.", "El tamaño del archivo ejecutable.", "La ubicación del archivo de configuración."], respuestaCorrecta: 1, explicacion: "systemctl status proporciona información completa: estado actual, si se inicia con el sistema, recursos usados y logs recientes." },
  { id: 11, curso: "Red Hat System Administration I", pregunta: "¿Cómo verías todos los servicios habilitados para iniciar con el sistema?", opciones: ["systemctl list-unit-files --state=enabled", "ps aux --enabled", "service --list-enabled", "chkconfig --on", "init --enabled"], respuestaCorrecta: 0, explicacion: "El comando systemctl list-unit-files filtrado por estado 'enabled' muestra todos los servicios configurados para iniciar automáticamente." },
  { id: 12, curso: "Red Hat System Administration I", pregunta: "¿Qué diferencia hay entre active, enabled y masked en systemctl?", opciones: ["active=corriendo, enabled=inicia con el sistema, masked=desactivado permanentemente.", "Son sinónimos.", "active=inicia con el sistema, enabled=corriendo, masked=pausado.", "masked=corriendo, enabled=detenido, active=eliminado.", "No existen esos estados."], respuestaCorrecta: 0, explicacion: "active indica que el servicio está ejecutándose, enabled que inicia automáticamente al arrancar, y masked que está completamente deshabilitado." },
  { id: 13, curso: "Red Hat System Administration I", pregunta: "¿Cómo crearías un servicio personalizado con systemd?", opciones: ["Creando un archivo .service en /etc/systemd/system/", "Ejecutando service create", "Usando el comando mkinitrd", "Editando /etc/init.d/", "No se pueden crear servicios personalizados."], respuestaCorrecta: 0, explicacion: "Se crea un archivo con extensión .service en el directorio /etc/systemd/system/ definiendo las directivas del servicio." },
  { id: 14, curso: "Red Hat System Administration I", pregunta: "¿Qué archivo usarías para definir una unidad de servicio personalizada?", opciones: ["/etc/systemd/system/mi_servicio.service", "/etc/init.d/mi_servicio", "/usr/bin/mi_servicio.conf", "/var/log/mi_servicio.log", "/etc/services/mi_servicio"], respuestaCorrecta: 0, explicacion: "Los archivos de unidad personalizados se crean en /etc/systemd/system/ con extensión .service." },
  { id: 15, curso: "Red Hat System Administration I", pregunta: "¿Cómo recargarías systemd después de modificar un archivo de servicio?", opciones: ["systemctl daemon-reload", "systemctl restart", "systemctl reload-all", "init reload", "service --refresh"], respuestaCorrecta: 0, explicacion: "daemon-reload hace que systemd relea todos los archivos de unidad para aplicar los cambios realizados." },
  { id: 16, curso: "Red Hat System Administration I", pregunta: "¿Cómo comprobarías el espacio usado por cada directorio de primer nivel?", opciones: ["df -h", "du -sh /*", "ls -lh", "free -h", "top -disk"], respuestaCorrecta: 1, explicacion: "du -sh /* muestra el tamaño total de cada directorio en el nivel raíz del sistema de archivos." },
  { id: 17, curso: "Red Hat System Administration I", pregunta: "¿Cómo localizarías los archivos más pesados en un sistema Linux?", opciones: ["find / -type f -exec ls -s {} + | sort -n | tail -10", "ls -lS / | head", "top --files", "du --heaviest", "locate --size large"], respuestaCorrecta: 0, explicacion: "Este comando combina find para buscar archivos, ls -s para mostrar tamaños, sort para ordenar y tail para mostrar los 10 más grandes." },
  { id: 18, curso: "Red Hat System Administration I", pregunta: "¿Qué comando usarías para verificar el sistema de archivos de una partición?", opciones: ["fsck /dev/sda1", "checkfs /dev/sda1", "verify /dev/sda1", "mount --check /dev/sda1", "diskcheck /dev/sda1"], respuestaCorrecta: 0, explicacion: "fsck (file system consistency check) verifica y repara inconsistencias en sistemas de archivos Linux." },
  { id: 19, curso: "Red Hat System Administration I", pregunta: "¿Qué riesgos existen al editar /etc/fstab incorrectamente?", opciones: ["Ninguno, es un archivo de configuración normal.", "El sistema podría no arrancar si hay errores en los puntos de montaje.", "Solo se perderían permisos de usuario.", "Se borrarían todos los archivos del sistema.", "Se desconfiguraría la red."], respuestaCorrecta: 1, explicacion: "Un error en /etc/fstab puede impedir que el sistema monte correctamente las particiones durante el arranque, causando fallos críticos." },
  { id: 20, curso: "Red Hat System Administration I", pregunta: "¿Cómo montarías manualmente una partición temporalmente?", opciones: ["mount /dev/sda1 /mnt", "addmount /dev/sda1 /mnt", "attach /dev/sda1 /mnt", "link /dev/sda1 /mnt", "connect /dev/sda1 /mnt"], respuestaCorrecta: 0, explicacion: "El comando mount con el dispositivo y el punto de montaje permite montar particiones manualmente, pero solo hasta el próximo reinicio." },
  { id: 21, curso: "Red Hat System Administration I", pregunta: "¿Cómo harías un montaje persistente al reiniciar?", opciones: ["Agregando una entrada en /etc/fstab", "Usando mount --permanent", "Ejecutando mkinitrd", "Configurando systemd-mount", "No es posible hacer montajes persistentes."], respuestaCorrecta: 0, explicacion: "El archivo /etc/fstab contiene las configuraciones de montaje que se aplican automáticamente en cada arranque del sistema." },
  { id: 22, curso: "Red Hat System Administration I", pregunta: "¿Qué diferencia hay entre df y du?", opciones: ["df muestra espacio libre en sistemas de archivos, du muestra espacio usado por archivos/directorios.", "Son exactamente lo mismo.", "df es para discos y du para USB.", "du es más rápido que df.", "df solo funciona con root."], respuestaCorrecta: 0, explicacion: "df (disk free) reporta espacio disponible en particiones montadas, mientras que du (disk usage) calcula el espacio consumido por archivos específicos." },
  { id: 23, curso: "Red Hat System Administration I", pregunta: "¿Cómo verificarías el tipo de sistema de archivos de una partición?", opciones: ["blkid /dev/sda1 o file -s /dev/sda1", "ls -l /dev/sda1", "cat /etc/fstype", "mount --type", "disktype /dev/sda1"], respuestaCorrecta: 0, explicacion: "blkid muestra información sobre dispositivos de bloque incluyendo el tipo de sistema de archivos, y file -s puede identificar sistemas de archivos." },
  { id: 24, curso: "Red Hat System Administration I", pregunta: "¿Qué hace blkid?", opciones: ["Muestra información de dispositivos de bloque como UUID y tipo de sistema de archivos.", "Crea nuevos dispositivos de bloque.", "Formatea particiones.", "Monta sistemas de archivos automáticamente.", "Verifica la integridad del disco."], respuestaCorrecta: 0, explicacion: "blkid (block ID) muestra atributos de dispositivos de bloque como UUID, LABEL y TYPE (tipo de sistema de archivos)." },
  { id: 25, curso: "Red Hat System Administration I", pregunta: "¿Cómo identificarías qué disco corresponde a una partición montada?", opciones: ["df -h muestra el dispositivo, lsblk muestra la relación disco-partición", "mount --show", "cat /proc/mounts", "fdisk -l", "blkid -all"], respuestaCorrecta: 0, explicacion: "df muestra qué dispositivo está montado, y lsblk muestra la jerarquía de discos y particiones para identificar la relación." },
  { id: 26, curso: "Red Hat System Administration I", pregunta: "¿Qué diferencia hay entre hard link y symlink en una situación real?", opciones: ["hard link apunta al mismo inodo, symlink es un acceso directo al archivo original.", "Son exactamente lo mismo.", "hard link funciona entre particiones, symlink no.", "symlink es más rápido que hard link.", "hard link solo funciona con root."], respuestaCorrecta: 0, explicacion: "Un hard link comparte el mismo inodo que el archivo original, mientras que un symlink (enlace simbólico) es un archivo separado que apunta a la ruta del original." },
  { id: 27, curso: "Red Hat System Administration I", pregunta: "¿Qué pasa si borras el archivo original de un enlace simbólico?", opciones: ["El symlink queda roto y no funciona.", "El symlink sigue funcionando normalmente.", "Se borra también el symlink automáticamente.", "El sistema crea un nuevo archivo automáticamente.", "El symlink se convierte en hard link."], respuestaCorrecta: 0, explicacion: "Un symlink depende de la ruta del archivo original. Si se borra el original, el enlace queda 'roto' porque apunta a una ruta inexistente." },
  { id: 28, curso: "Red Hat System Administration I", pregunta: "¿Cómo duplicarías una estructura de permisos entre dos carpetas?", opciones: ["chmod --reference=carpeta1 carpeta2", "cp --perms carpeta1 carpeta2", "rsync --perms carpeta1/ carpeta2/", "getfacl carpeta1 | setfacl carpeta2", "chmod -R carpeta1 carpeta2"], respuestaCorrecta: 0, explicacion: "chmod --reference copia los permisos de un archivo o directorio de referencia a otro, replicando exactamente la estructura de permisos." },
  { id: 29, curso: "Red Hat System Administration I", pregunta: "¿Cómo buscarías archivos con un nombre parcial en todo el sistema?", opciones: ["find / -name '*parcial*'", "locate parcial", "search --name parcial", "grep -r parcial /", "find --partial nombre"], respuestaCorrecta: 0, explicacion: "find con el comodín * permite buscar archivos que contengan el texto parcial en cualquier parte de su nombre en todo el sistema." },
  { id: 30, curso: "Red Hat System Administration I", pregunta: "¿Qué hace find que no hace locate?", opciones: ["find busca en tiempo real en el sistema de archivos, locate usa una base de datos pre-generada.", "locate es más preciso que find.", "find solo busca archivos, locate busca todo.", "locate puede buscar por contenido.", "find es más rápido siempre."], respuestaCorrecta: 0, explicacion: "find examina el sistema de archivos en tiempo real, mientras que locate consulta una base de datos que debe actualizarse periódicamente con updatedb." },
  { id: 31, curso: "Red Hat System Administration I", pregunta: "¿Cómo cambiarías la propiedad de una carpeta y todo su contenido?", opciones: ["chown -R usuario:grupo carpeta", "chown --all usuario:grupo carpeta", "chmod -R usuario:grupo carpeta", "setowner -R usuario:grupo carpeta", "propiedad -R usuario:grupo carpeta"], respuestaCorrecta: 0, explicacion: "chown (change owner) con la opción -R cambia recursivamente el propietario y grupo de la carpeta y todo su contenido." },
  { id: 32, curso: "Red Hat System Administration I", pregunta: "¿Cómo listarías los usuarios conectados al sistema?", opciones: ["who o w", "ps users", "ls /home", "cat /etc/passwd", "users --connected"], respuestaCorrecta: 0, explicacion: "who muestra los usuarios actualmente conectados, y w proporciona información más detallada incluyendo qué están haciendo." },
  { id: 33, curso: "Red Hat System Administration I", pregunta: "¿Cómo verías el historial de autenticación de un usuario?", opciones: ["last usuario", "grep usuario /var/log/auth.log", "history usuario", "authlog usuario", "journalctl -u usuario"], respuestaCorrecta: 0, explicacion: "El comando last muestra el historial de inicios de sesión de todos los usuarios o de un usuario específico, leyendo /var/log/wtmp." },
  { id: 34, curso: "Red Hat System Administration I", pregunta: "¿Cómo bloquearías temporalmente una cuenta de usuario?", opciones: ["usermod -L usuario", "passwd -l usuario", "lockuser usuario", "account --block usuario", "disable usuario"], respuestaCorrecta: 0, explicacion: "usermod -L (lock) bloquea la cuenta del usuario impidiendo el inicio de sesión, pero mantiene todos sus archivos y configuraciones." },
  { id: 35, curso: "Red Hat System Administration I", pregunta: "¿Qué diferencia hay entre su y sudo en administración diaria?", opciones: ["su cambia de usuario completamente, sudo ejecuta comandos específicos con privilegios.", "Son exactamente lo mismo.", "sudo es más seguro que su siempre.", "su solo funciona con root.", "sudo no requiere contraseña nunca."], respuestaCorrecta: 0, explicacion: "su (switch user) cambia al usuario destino, mientras que sudo permite ejecutar comandos específicos como otro usuario (generalmente root) sin cambiar de sesión." },
  { id: 36, curso: "Red Hat System Administration I", pregunta: "¿Cómo agregarías un usuario a varios grupos a la vez?", opciones: ["usermod -aG grupo1,grupo2,grupo3 usuario", "addgroup usuario grupo1 grupo2 grupo3", "groupadd usuario grupo1,grupo2", "setgroups usuario grupo1 grupo2", "usermod --groups usuario grupo1,grupo2"], respuestaCorrecta: 0, explicacion: "usermod con -aG (append to Groups) agrega el usuario a los grupos especificados sin eliminarlo de otros grupos a los que ya pertenece." },
  { id: 37, curso: "Red Hat System Administration I", pregunta: "¿Cómo comprobarías a qué grupos pertenece un usuario?", opciones: ["groups usuario o id usuario", "ls -l /home/usuario", "cat /etc/group | grep usuario", "whoami --groups", "usergroups usuario"], respuestaCorrecta: 0, explicacion: "El comando groups muestra todos los grupos a los que pertenece un usuario, e id muestra información más detallada incluyendo UID y GID." },
  { id: 38, curso: "Red Hat System Administration I", pregunta: "¿Qué archivo almacena información de grupos del sistema?", opciones: ["/etc/group", "/etc/groups", "/var/groups", "/etc/passwd", "/etc/users"], respuestaCorrecta: 0, explicacion: "El archivo /etc/group contiene la lista de todos los grupos del sistema con sus respectivos miembros y GID." },
  { id: 39, curso: "Red Hat System Administration I", pregunta: "¿Cómo crearías un usuario sin directorio home?", opciones: ["useradd -M usuario", "useradd --no-home usuario", "adduser -nohome usuario", "newuser --skip-home usuario", "createuser -M usuario"], respuestaCorrecta: 0, explicacion: "La opción -M (no create home) de useradd crea el usuario sin generar automáticamente su directorio personal en /home." },
  { id: 40, curso: "Red Hat System Administration I", pregunta: "¿Cómo establecerías una fecha de expiración para una cuenta?", opciones: ["usermod -e AAAA-MM-DD usuario", "chage -E AAAA-MM-DD usuario", "expireuser -d AAAA-MM-DD usuario", "account --expire AAAA-MM-DD usuario", "setexpiry usuario AAAA-MM-DD"], respuestaCorrecta: 0, explicacion: "usermod -e establece la fecha de expiración de la cuenta en formato AAAA-MM-DD, después de la cual el usuario no podrá iniciar sesión." },
  { id: 41, curso: "Red Hat System Administration I", pregunta: "¿Cómo configurarías una contraseña para que expire?", opciones: ["chage -M dias usuario", "passwd --expire usuario", "usermod --pass-expire usuario", "setpass --max-age dias usuario", "password --expire dias usuario"], respuestaCorrecta: 0, explicacion: "chage -M (max days) establece el número máximo de días que la contraseña es válida antes de que expire y deba cambiarse." },
  { id: 42, curso: "Red Hat System Administration I", pregunta: "¿Qué utilidad tiene visudo?", opciones: ["Edita el archivo sudoers con validación de sintaxis para evitar errores.", "Crea nuevos usuarios sudo.", "Elimina usuarios del grupo sudo.", "Cambia la contraseña de root.", "Lista todos los comandos permitidos con sudo."], respuestaCorrecta: 0, explicacion: "visudo edita /etc/sudoers de forma segura, verificando la sintaxis antes de guardar para evitar bloquear el acceso sudo por errores." },
  { id: 43, curso: "Red Hat System Administration I", pregunta: "¿Por qué no conviene editar sudoers directamente con un editor normal?", opciones: ["Un error de sintaxis puede bloquear completamente el acceso sudo al sistema.", "Es más lento que visudo.", "No se pueden hacer cambios permanentes.", "Requiere reiniciar el sistema.", "Solo funciona en modo recuperación."], respuestaCorrecta: 0, explicacion: "Si hay un error de sintaxis en /etc/sudoers, el comando sudo dejará de funcionar completamente, pudiendo bloquear el acceso administrativo." },
  { id: 44, curso: "Red Hat System Administration I", pregunta: "¿Cómo revisarías el contenido de un archivo protegido sin abrirlo con editor?", opciones: ["cat archivo o less archivo", "view archivo", "read archivo", "show archivo", "display archivo"], respuestaCorrecta: 0, explicacion: "cat muestra el contenido completo, y less permite navegar por el contenido sin modificar el archivo, ambos solo requieren permisos de lectura." },
  { id: 45, curso: "Red Hat System Administration I", pregunta: "¿Cómo copiarías directorios preservando atributos?", opciones: ["cp -a origen destino", "cp -r origen destino", "copy --preserve origen destino", "rsync origen destino", "cp --all origen destino"], respuestaCorrecta: 0, explicacion: "cp -a (archive) copia recursivamente preservando permisos, propietarios, marcas de tiempo y enlaces simbólicos." },
  { id: 46, curso: "Red Hat System Administration I", pregunta: "¿Qué diferencia existe entre cp -r y cp -a?", opciones: ["cp -r copia recursivamente, cp -a copia recursivamente preservando todos los atributos.", "Son exactamente lo mismo.", "cp -a es más rápido que cp -r.", "cp -r preserva atributos, cp -a no.", "cp -a solo funciona con root."], respuestaCorrecta: 0, explicacion: "cp -r copia directorios y su contenido, mientras que cp -a hace lo mismo pero además preserva permisos, propietarios, marcas de tiempo y enlaces." },
  { id: 47, curso: "Red Hat System Administration I", pregunta: "¿Cómo comprimirías un directorio usando tar y gzip?", opciones: ["tar -czf archivo.tar.gz directorio", "tar -xz archivo.tar.gz directorio", "gzip directorio", "compress -tar directorio", "zip -r archivo.tar.gz directorio"], respuestaCorrecta: 0, explicacion: "tar -czf crea un archivo tar comprimido con gzip: -c (create), -z (gzip), -f (file). Empaqueta y comprime en un solo paso." },
  { id: 48, curso: "Red Hat System Administration I", pregunta: "¿Cómo listarías el contenido de un archivo .tar.gz sin extraerlo?", opciones: ["tar -tzf archivo.tar.gz", "tar -xzf archivo.tar.gz", "ls archivo.tar.gz", "cat archivo.tar.gz", "view archivo.tar.gz"], respuestaCorrecta: 0, explicacion: "tar -tzf lista el contenido: -t (list), -z (gzip), -f (file). Muestra los archivos sin extraerlos del comprimido." },
  { id: 49, curso: "Red Hat System Administration I", pregunta: "¿Cómo extraerías un archivo comprimido en una ruta específica?", opciones: ["tar -xzf archivo.tar.gz -C /ruta/destino", "tar -xzf archivo.tar.gz /ruta/destino", "unzip archivo.tar.gz -d /ruta/destino", "extract archivo.tar.gz /ruta/destino", "tar --extract archivo.tar.gz /ruta/destino"], respuestaCorrecta: 0, explicacion: "La opción -C de tar permite especificar el directorio de destino donde se extraerá el contenido del archivo comprimido." },
  { id: 50, curso: "Red Hat System Administration I", pregunta: "¿Cómo verificarías qué versión del kernel está ejecutando el sistema?", opciones: ["uname -r", "cat /etc/kernel", "version --kernel", "kernel --version", "sysinfo kernel"], respuestaCorrecta: 0, explicacion: "uname -r (release) muestra específicamente la versión del kernel que está ejecutándose actualmente en el sistema." },
  { id: 51, curso: "CCNA M3", pregunta: "¿Cómo elegirías entre una ruta estática y un protocolo dinámico en una red pequeña?", opciones: ["En redes pequeñas y estáticas, las rutas estáticas son más simples y eficientes.", "Siempre usar dinámico porque es más moderno.", "Las estáticas nunca son recomendables.", "Depende solo del fabricante del router.", "Los protocolos dinámicos no funcionan en redes pequeñas."], respuestaCorrecta: 0, explicacion: "En redes pequeñas con pocos cambios, las rutas estáticas requieren menos recursos y son más predecibles que los protocolos dinámicos." },
  { id: 52, curso: "CCNA M3", pregunta: "¿Qué problema resuelve el enrutamiento inter-área en OSPF?", opciones: ["Permite conectar múltiples áreas OSPF y compartir rutas entre ellas.", "Aumenta la velocidad de convergencia.", "Reduce el consumo de CPU.", "Elimina la necesidad de un ABR.", "Simplifica la configuración de una sola área."], respuestaCorrecta: 0, explicacion: "El enrutamiento inter-área permite que routers en diferentes áreas OSPF intercambien información de rutas a través de un ABR (Area Border Router)." },
  { id: 53, curso: "CCNA M3", pregunta: "¿Qué diferencia hay entre OSPF de área única y multiarea?", opciones: ["Multiarea divide la red en áreas para mejor escalabilidad y menor overhead.", "Son exactamente lo mismo.", "Área única es más rápida siempre.", "Multiarea requiere más memoria.", "Área única no soporta VLSM."], respuestaCorrecta: 0, explicacion: "OSPF multiarea divide la red en áreas jerárquicas, reduciendo el tamaño de las tablas de topología y mejorando la escalabilidad." },
  { id: 54, curso: "CCNA M3", pregunta: "¿Qué significa que un router sea ABR?", opciones: ["Area Border Router: conecta el área 0 con otras áreas OSPF.", "Automatic Backup Router.", "Advanced Border Routing.", "Active Backup Route.", "Area Base Router."], respuestaCorrecta: 0, explicacion: "Un ABR (Area Border Router) tiene interfaces en múltiples áreas OSPF, incluyendo el backbone (área 0), y mantiene bases de datos separadas para cada área." },
  { id: 55, curso: "CCNA M3", pregunta: "¿Qué significa que un router sea ASBR?", opciones: ["Autonomous System Boundary Router: conecta OSPF con otros sistemas autónomos o protocolos.", "Active System Base Router.", "Automatic Static Border Router.", "Advanced System Backup Router.", "Area Standard Border Router."], respuestaCorrecta: 0, explicacion: "Un ASBR conecta el sistema autónomo OSPF con otros sistemas autónomos o protocolos de enrutamiento externos como EIGRP o BGP." },
  { id: 56, curso: "CCNA M3", pregunta: "¿Cómo afecta el costo OSPF a la selección de mejor ruta?", opciones: ["OSPF elige la ruta con menor costo acumulado hasta el destino.", "El costo no afecta la selección de rutas.", "OSPF elige la ruta con mayor costo.", "El costo solo se usa como respaldo.", "El costo se calcula solo por número de saltos."], respuestaCorrecta: 0, explicacion: "OSPF calcula el costo basado en el ancho de banda de cada interfaz y selecciona la ruta con el menor costo total acumulado." },
  { id: 57, curso: "CCNA M3", pregunta: "¿Cómo cambiarías el costo de una interfaz en OSPF?", opciones: ["ip ospf cost <valor> bajo la interfaz", "ospf cost <valor> global", "set ospf-cost <valor>", "cost ospf <valor> interface", "router ospf cost <valor>"], respuestaCorrecta: 0, explicacion: "El comando ip ospf cost bajo la configuración de la interfaz permite sobrescribir manualmente el costo calculado automáticamente." },
  { id: 58, curso: "CCNA M3", pregunta: "¿Qué comando usarías para ver la base de datos OSPF?", opciones: ["show ip ospf database", "show ospf routes", "show ip ospf topology", "show ospf lsdb", "display ospf database"], respuestaCorrecta: 0, explicacion: "show ip ospf database muestra todos los LSAs (Link State Advertisements) que el router ha recibido y almacenado en su base de datos." },
  { id: 59, curso: "CCNA M3", pregunta: "¿Qué información muestra el router ID en OSPF?", opciones: ["Identificador único de 32 bits del router en el dominio OSPF.", "La dirección MAC del router.", "El nombre del fabricante.", "La versión de IOS.", "El número de serie del equipo."], respuestaCorrecta: 0, explicacion: "El Router ID es un identificador único de 32 bits (formato IP) que identifica a cada router dentro del sistema autónomo OSPF." },
  { id: 60, curso: "CCNA M3", pregunta: "¿Cómo se elige el router ID si no se configura manualmente?", opciones: ["La dirección IP más alta de interfaces loopback, o si no hay, la IP más alta de interfaces activas.", "La dirección IP más baja de cualquier interfaz.", "Aleatoriamente al iniciar OSPF.", "Por orden de activación de interfaces.", "Usa la dirección MAC convertida a IP."], respuestaCorrecta: 0, explicacion: "OSPF selecciona automáticamente el Router ID tomando la IP más alta de interfaces loopback, o si no existen, la IP más alta entre interfaces activas." },
  { id: 61, curso: "CCNA M3", pregunta: "¿Qué ocurre cuando dos routers OSPF tienen temporizadores distintos?", opciones: ["No pueden formar adyacencia porque los hello/dead intervals deben coincidir.", "Forman adyacencia pero con convergencia lenta.", "Funcionan normalmente sin problemas.", "El router con temporizadores más rápidos domina.", "Se forma adyacencia parcial."], respuestaCorrecta: 0, explicacion: "Para formar adyacencia OSPF, los temporizadores Hello y Dead deben coincidir exactamente entre vecinos, de lo contrario no establecen relación." },
  { id: 62, curso: "CCNA M3", pregunta: "¿Qué temporizadores deben coincidir para formar vecindad OSPF?", opciones: ["Hello interval y Dead interval.", "Solo el Hello interval.", "Solo el Dead interval.", "SPF delay y SPF holdtime.", "LSA refresh y LS age."], respuestaCorrecta: 0, explicacion: "Los temporizadores Hello (frecuencia de saludos) y Dead (tiempo para declarar vecino caído) deben ser idénticos entre routers vecinos." },
  { id: 63, curso: "CCNA M3", pregunta: "¿Cómo verificarías el estado de una adyacencia OSPF?", opciones: ["show ip ospf neighbor", "show ospf adjacency", "show ip ospf interface", "show ospf status", "display ospf peer"], respuestaCorrecta: 0, explicacion: "show ip ospf neighbor muestra todos los vecinos OSPF, su estado (INIT, 2-WAY, EXSTART, EXCHANGE, LOADING, FULL), y detalles de la adyacencia." },
  { id: 64, curso: "CCNA M3", pregunta: "¿Qué significa el estado FULL en OSPF?", opciones: ["Los routers han sincronizado completamente sus bases de datos de topología.", "El router está completamente cargado de memoria.", "La interfaz está al máximo de su capacidad.", "Se han establecido todas las rutas posibles.", "El router tiene todos los vecinos conectados."], respuestaCorrecta: 0, explicacion: "FULL indica que los routers vecinos han completado el intercambio de bases de datos y tienen información de topología idéntica." },
  { id: 65, curso: "CCNA M3", pregunta: "¿Qué puede causar que OSPF quede atascado en estado EXSTART?", opciones: ["Discrepancia en el MTU de las interfaces conectadas.", "Temporizadores diferentes.", "Áreas diferentes.", "Router IDs duplicados.", "Costos incompatibles."], respuestaCorrecta: 0, explicacion: "Si el MTU no coincide entre interfaces vecinas, OSPF puede quedar atrapado en EXSTART porque no pueden intercambiar paquetes DBD correctamente." },
  { id: 66, curso: "CCNA M3", pregunta: "¿Cómo funciona el proceso de elección de DR y BDR?", opciones: ["Se elige el router con mayor prioridad OSPF, y en empate, el mayor Router ID.", "Se elige aleatoriamente.", "El primer router que inicia OSPF es DR.", "Se elige por orden de dirección IP más baja.", "El router con más vecinos es DR."], respuestaCorrecta: 0, explicacion: "La elección de DR/BDR se basa primero en la prioridad OSPF (por defecto 1), y si hay empate, gana el router con el Router ID más alto." },
  { id: 67, curso: "CCNA M3", pregunta: "¿Por qué en una red broadcast se elige DR/BDR?", opciones: ["Para reducir el número de adyacencias completas y optimizar el intercambio de LSAs.", "Para aumentar la seguridad de la red.", "Para balancear la carga de tráfico.", "Para permitir múltiples puertas de enlace.", "Para simplificar la configuración."], respuestaCorrecta: 0, explicacion: "En redes broadcast con múltiples routers, DR/BDR reduce las adyacencias FULL de N*(N-1)/2 a N-1, optimizando el uso de recursos." },
  { id: 68, curso: "CCNA M3", pregunta: "¿Qué pasa en OSPF si una interfaz se configura como pasiva?", opciones: ["La interfaz no envía paquetes Hello ni forma adyacencias, pero la red se anuncia.", "La interfaz se desactiva completamente.", "La interfaz solo recibe rutas, no las envía.", "La interfaz funciona normalmente pero con prioridad baja.", "La interfaz se convierte en backup."], respuestaCorrecta: 0, explicacion: "Una interfaz pasiva no establece adyacencias OSPF (no envía Hello), pero la red conectada a esa interfaz sí se anuncia en OSPF." },
  { id: 69, curso: "CCNA M3", pregunta: "¿Cómo evitarías anunciar una interfaz específica en OSPF sin apagarla?", opciones: ["Configurándola como passive-interface en el proceso OSPF.", "Eliminando la red del comando network.", "Usando distribute-list.", "Apagando la interfaz con shutdown.", "Cambiando el área de la interfaz."], respuestaCorrecta: 0, explicacion: "passive-interface hace que la interfaz no forme adyacencias OSPF pero permite que la red conectada sea anunciada a otros routers." },
  { id: 70, curso: "CCNA M3", pregunta: "¿Qué diferencia hay entre network y passive-interface en OSPF?", opciones: ["network activa OSPF en una interfaz, passive-interface evita que forme adyacencias pero anuncia la red.", "Son lo mismo.", "network es para áreas, passive-interface para interfaces.", "passive-interface desactiva completamente OSPF.", "network solo funciona con áreas 0."], respuestaCorrecta: 0, explicacion: "El comando network habilita OSPF en interfaces que coincidan, mientras que passive-interface modifica el comportamiento para no formar adyacencias en esa interfaz." },
  { id: 71, curso: "CCNA M3", pregunta: "¿Cómo sumarizarías rutas en un área OSPF?", opciones: ["Usando el comando area <area> range <red> <máscara> en el ABR.", "Con el comando summary-address global.", "OSPF no soporta sumarización.", "Usando redistribute summary.", "Con el comando network summary."], respuestaCorrecta: 0, explicacion: "La sumarización inter-área se configura en el ABR con el comando area range, agrupando múltiples rutas en una sola antes de anunciarlas a otras áreas." },
  { id: 72, curso: "CCNA M3", pregunta: "¿En qué punto de la red conviene hacer sumarización?", opciones: ["En los ABR entre áreas o en ASBR entre protocolos.", "En todos los routers de la red.", "Solo en el router central.", "En las interfaces de acceso.", "En los switches de distribución."], respuestaCorrecta: 0, explicacion: "La sumarización debe hacerse en los límites de áreas (ABR) o entre protocolos (ASBR) para reducir el tamaño de tablas y mejorar la estabilidad." },
  { id: 73, curso: "CCNA M3", pregunta: "¿Qué ventaja tiene la sumarización en una red empresarial?", opciones: ["Reduce el tamaño de tablas de enrutamiento y limita el impacto de cambios de topología.", "Aumenta el ancho de banda disponible.", "Mejora la seguridad de la red.", "Elimina la necesidad de protocolos dinámicos.", "Acelera la velocidad de las interfaces."], respuestaCorrecta: 0, explicacion: "La sumarización reduce la cantidad de rutas en tablas, disminuye el overhead de actualizaciones y contiene fallos dentro de áreas específicas." },
  { id: 74, curso: "CCNA M3", pregunta: "¿Qué es una ruta flotante?", opciones: ["Una ruta estática de respaldo con mayor distancia administrativa que la ruta principal.", "Una ruta que cambia dinámicamente según la carga.", "Una ruta temporal que se elimina después de un tiempo.", "Una ruta que flota entre múltiples protocolos.", "Una ruta inalámbrica."], respuestaCorrecta: 0, explicacion: "Una ruta flotante es una ruta estática configurada con una distancia administrativa mayor que la ruta principal, activándose solo si la ruta principal falla." },
  { id: 75, curso: "CCNA M3", pregunta: "¿Cómo se define una distancia administrativa para una ruta estática de respaldo?", opciones: ["ip route <red> <máscara> <next-hop> <distancia-administrativa>", "route backup <red> <máscara> <next-hop>", "static-route <red> <máscara> <next-hop> priority <valor>", "ip route floating <red> <máscara> <next-hop>", "backup-route <red> <máscara> <next-hop> <AD>"], respuestaCorrecta: 0, explicacion: "Al final del comando ip route se puede especificar una distancia administrativa personalizada (por defecto 1 para estáticas), valores mayores crean rutas de respaldo." },
  { id: 76, curso: "CCNA M3", pregunta: "¿Qué ocurre si una ruta estática y una dinámica apuntan al mismo destino?", opciones: ["El router instala la que tenga menor distancia administrativa en la tabla de enrutamiento.", "Se instalan ambas y se balancea la carga.", "La ruta estática siempre gana.", "La ruta dinámica siempre gana.", "Se genera un error de configuración."], respuestaCorrecta: 0, explicacion: "El router compara las distancias administrativas y selecciona la ruta con menor valor (por defecto: estática=1, OSPF=110, etc.) para instalar en la tabla." },
  { id: 77, curso: "CCNA M3", pregunta: "¿Cómo verificarías qué ruta está usando el router para un destino específico?", opciones: ["show ip route <red destino>", "traceroute <destino>", "ping <destino>", "show ip ospf route", "show route <destino>"], respuestaCorrecta: 0, explicacion: "show ip route muestra la tabla de enrutamiento completa, y al especificar una red muestra específicamente qué ruta está instalada y activa para ese destino." },
  { id: 78, curso: "CCNA M3", pregunta: "¿Qué significa que una red tenga convergencia rápida?", opciones: ["Todos los routers actualizan sus tablas rápidamente después de un cambio de topología.", "La red tiene alto ancho de banda.", "Los routers tienen mucha memoria.", "La red soporta muchos protocolos simultáneamente.", "Los enlaces son de fibra óptica."], respuestaCorrecta: 0, explicacion: "Convergencia rápida significa que todos los routers del dominio de enrutamiento recalculan y actualizan sus tablas en el menor tiempo posible tras un cambio." },
  { id: 79, curso: "CCNA M3", pregunta: "¿Cómo se comporta el router cuando desaparece una red aprendida por OSPF?", opciones: ["Ejecuta el algoritmo SPF para recalcular las mejores rutas disponibles.", "Mantiene la ruta indefinidamente.", "Borra toda la tabla de enrutamiento.", "Cambia automáticamente a RIP.", "Espera a que un administrador reconfigure manualmente."], respuestaCorrecta: 0, explicacion: "Cuando OSPF detecta que una red desaparece (LSA de actualización), ejecuta el algoritmo SPF para recalcular las rutas óptimas basándose en la nueva topología." },
  { id: 80, curso: "CCNA M3", pregunta: "¿Qué información aporta show ip ospf neighbor?", opciones: ["Lista de vecinos OSPF, su estado, prioridad, Router ID y dirección.", "Solo el estado de las interfaces OSPF.", "Las rutas aprendidas por OSPF.", "La base de datos completa de LSAs.", "Los temporizadores de todas las áreas."], respuestaCorrecta: 0, explicacion: "show ip ospf neighbor muestra detalles de cada vecino: estado de adyacencia, prioridad, Router ID, dirección IP de la interfaz vecina y tiempo desde el último Hello." },
  { id: 81, curso: "CCNA M3", pregunta: "¿Qué diferencia hay entre routing de capa 3 y switching de capa 2?", opciones: ["Routing toma decisiones basadas en IP, switching basado en MAC.", "Routing es más rápido que switching.", "Switching funciona entre redes diferentes.", "Routing solo usa protocolos dinámicos.", "Switching requiere configuración de rutas."], respuestaCorrecta: 0, explicacion: "El routing (capa 3) enruta paquetes entre redes diferentes usando direcciones IP, mientras que el switching (capa 2) reenvía tramas dentro de la misma red usando direcciones MAC." },
  { id: 82, curso: "CCNA M3", pregunta: "¿Qué rol cumple el router en una red con múltiples subredes?", opciones: ["Interconecta las subredes y enruta tráfico entre ellas.", "Solo conecta dispositivos dentro de la misma subred.", "Asigna direcciones IP automáticamente.", "Filtra tráfico por direcciones MAC.", "Proporciona energía a los dispositivos."], respuestaCorrecta: 0, explicacion: "El router actúa como gateway entre subredes, tomando decisiones de enrutamiento basadas en direcciones IP para permitir la comunicación entre redes diferentes." },
  { id: 83, curso: "CCNA M3", pregunta: "¿Qué es una ruta resumen manual?", opciones: ["Una ruta configurada manualmente para representar múltiples redes más específicas.", "Una ruta aprendida automáticamente por OSPF.", "Una ruta estática con baja distancia administrativa.", "Una ruta que resume el historial de cambios.", "Una ruta temporal de prueba."], respuestaCorrecta: 0, explicacion: "Una ruta resumen manual agrupa múltiples redes en una sola entrada de tabla de enrutamiento, reduciendo el tamaño de la tabla y las actualizaciones." },
  { id: 84, curso: "CCNA M3", pregunta: "¿Qué es el enrutamiento classless?", opciones: ["Enrutamiento que usa máscaras de longitud variable (VLSM) y no se basa en clases A, B, C.", "Enrutamiento sin protocolos.", "Enrutamiento que solo funciona con IPv6.", "Enrutamiento que no usa tablas.", "Enrutamiento exclusivo de redes pequeñas."], respuestaCorrecta: 0, explicacion: "El enrutamiento classless (como RIPv2, OSPF, EIGRP) soporta VLSM y CIDR, permitiendo máscaras de subred variables y un uso más eficiente del espacio de direcciones." },
  { id: 85, curso: "CCNA M3", pregunta: "¿Por qué CIDR fue importante para el crecimiento de Internet?", opciones: ["Permitió un uso más eficiente del espacio de direcciones IP mediante agregación de rutas.", "Aumentó la velocidad de transmisión.", "Eliminó la necesidad de NAT.", "Hizo obsoletos los protocolos de enrutamiento.", "Permitió redes ilimitadas."], respuestaCorrecta: 0, explicacion: "CIDR (Classless Inter-Domain Routing) permitió la agregación de rutas y un uso más eficiente de las direcciones IP, retrasando el agotamiento de IPv4." },
  { id: 86, curso: "CCNA M3", pregunta: "¿Cómo ayuda VLSM a aprovechar mejor el espacio de direcciones?", opciones: ["Permite usar diferentes máscaras de subred según el tamaño necesario de cada red.", "Asigna direcciones automáticamente.", "Comprime las direcciones IP.", "Elimina las direcciones privadas.", "Usa solo direcciones IPv6."], respuestaCorrecta: 0, explicacion: "VLSM (Variable Length Subnet Mask) permite asignar máscaras de subred específicas al tamaño real de cada red, minimizando el desperdicio de direcciones." },
  { id: 87, curso: "CCNA M3", pregunta: "¿Cómo calcularías subredes con VLSM para varios departamentos?", opciones: ["Asignando subredes más grandes a departamentos con más hosts y menores a los más pequeños.", "Usando la misma máscara para todos los departamentos.", "Asignando aleatoriamente las direcciones.", "Usando solo subredes de tamaño fijo.", "Dividiendo siempre en 2 subredes iguales."], respuestaCorrecta: 0, explicacion: "Con VLSM se asignan bloques de direcciones según las necesidades reales: departamentos grandes reciben subredes con más hosts, los pequeños subredes menores." },
  { id: 88, curso: "CCNA M3", pregunta: "¿Qué problema aparece si se usa una máscara incorrecta en una interfaz?", opciones: ["Puede causar problemas de conectividad porque el router calcula mal qué redes están directamente conectadas.", "No hay ningún problema.", "Solo afecta la velocidad.", "El router se reinicia automáticamente.", "Se borra la configuración."], respuestaCorrecta: 0, explicacion: "Una máscara incorrecta hace que el router interprete mal el rango de direcciones de la red local, causando problemas de enrutamiento y conectividad." },
  { id: 89, curso: "CCNA M3", pregunta: "¿Cómo diagnosticarías pérdida de conectividad entre dos routers?", opciones: ["Usando ping para verificar reachability y traceroute para identificar dónde se pierde el tráfico.", "Solo revisando el estado físico de los cables.", "Reiniciando ambos routers.", "Cambiando las direcciones IP.", "Desactivando el firewall."], respuestaCorrecta: 0, explicacion: "ping verifica si hay conectividad básica, y traceroute muestra cada salto intermedio, permitiendo identificar exactamente dónde se pierde la conectividad." },
  { id: 90, curso: "CCNA M3", pregunta: "¿Qué comandos usarías para revisar la tabla de rutas y la conectividad entre saltos?", opciones: ["show ip route y traceroute <destino>", "show interfaces y ping", "show ip ospf y show ip bgp", "debug ip routing y show running-config", "show version y show clock"], respuestaCorrecta: 0, explicacion: "show ip route muestra la tabla de enrutamiento completa, y traceroute permite verificar la ruta que toman los paquetes hacia un destino específico." },
  { id: 91, curso: "CCNA M3", pregunta: "¿Qué diferencia hay entre routing de capa 3 y switching de capa 2?", opciones: ["Routing toma decisiones basadas en IP, switching basado en MAC.", "Routing es más rápido que switching.", "Switching funciona entre redes diferentes.", "Routing solo usa protocolos dinámicos.", "Switching requiere configuración de rutas."], respuestaCorrecta: 0, explicacion: "El routing (capa 3) enruta paquetes entre redes diferentes usando direcciones IP, mientras que el switching (capa 2) reenvía tramas dentro de la misma red usando direcciones MAC." },
  { id: 92, curso: "CCNA M3", pregunta: "¿Qué rol cumple el router en una red con múltiples subredes?", opciones: ["Interconecta las subredes y enruta tráfico entre ellas.", "Solo conecta dispositivos dentro de la misma subred.", "Asigna direcciones IP automáticamente.", "Filtra tráfico por direcciones MAC.", "Proporciona energía a los dispositivos."], respuestaCorrecta: 0, explicacion: "El router actúa como gateway entre subredes, tomando decisiones de enrutamiento basadas en direcciones IP para permitir la comunicación entre redes diferentes." },
  { id: 93, curso: "CCNA M3", pregunta: "¿Qué es una ruta resumen manual?", opciones: ["Una ruta configurada manualmente para representar múltiples redes más específicas.", "Una ruta aprendida automáticamente por OSPF.", "Una ruta estática con baja distancia administrativa.", "Una ruta que resume el historial de cambios.", "Una ruta temporal de prueba."], respuestaCorrecta: 0, explicacion: "Una ruta resumen manual agrupa múltiples redes en una sola entrada de tabla de enrutamiento, reduciendo el tamaño de la tabla y las actualizaciones." },
  { id: 94, curso: "CCNA M3", pregunta: "¿Qué es el enrutamiento classless?", opciones: ["Enrutamiento que usa máscaras de longitud variable (VLSM) y no se basa en clases A, B, C.", "Enrutamiento sin protocolos.", "Enrutamiento que solo funciona con IPv6.", "Enrutamiento que no usa tablas.", "Enrutamiento exclusivo de redes pequeñas."], respuestaCorrecta: 0, explicacion: "El enrutamiento classless (como RIPv2, OSPF, EIGRP) soporta VLSM y CIDR, permitiendo máscaras de subred variables y un uso más eficiente del espacio de direcciones." },
  { id: 95, curso: "CCNA M3", pregunta: "¿Por qué CIDR fue importante para el crecimiento de Internet?", opciones: ["Permitió un uso más eficiente del espacio de direcciones IP mediante agregación de rutas.", "Aumentó la velocidad de transmisión.", "Eliminó la necesidad de NAT.", "Hizo obsoletos los protocolos de enrutamiento.", "Permitió redes ilimitadas."], respuestaCorrecta: 0, explicacion: "CIDR (Classless Inter-Domain Routing) permitió la agregación de rutas y un uso más eficiente de las direcciones IP, retrasando el agotamiento de IPv4." },
  { id: 96, curso: "CCNA M3", pregunta: "¿Cómo ayuda VLSM a aprovechar mejor el espacio de direcciones?", opciones: ["Permite usar diferentes máscaras de subred según el tamaño necesario de cada red.", "Asigna direcciones automáticamente.", "Comprime las direcciones IP.", "Elimina las direcciones privadas.", "Usa solo direcciones IPv6."], respuestaCorrecta: 0, explicacion: "VLSM (Variable Length Subnet Mask) permite asignar máscaras de subred específicas al tamaño real de cada red, minimizando el desperdicio de direcciones." },
  { id: 97, curso: "CCNA M3", pregunta: "¿Cómo calcularías subredes con VLSM para varios departamentos?", opciones: ["Asignando subredes más grandes a departamentos con más hosts y menores a los más pequeños.", "Usando la misma máscara para todos los departamentos.", "Asignando aleatoriamente las direcciones.", "Usando solo subredes de tamaño fijo.", "Dividiendo siempre en 2 subredes iguales."], respuestaCorrecta: 0, explicacion: "Con VLSM se asignan bloques de direcciones según las necesidades reales: departamentos grandes reciben subredes con más hosts, los pequeños subredes menores." },
  { id: 98, curso: "CCNA M3", pregunta: "¿Qué problema aparece si se usa una máscara incorrecta en una interfaz?", opciones: ["Puede causar problemas de conectividad porque el router calcula mal qué redes están directamente conectadas.", "No hay ningún problema.", "Solo afecta la velocidad.", "El router se reinicia automáticamente.", "Se borra la configuración."], respuestaCorrecta: 0, explicacion: "Una máscara incorrecta hace que el router interprete mal el rango de direcciones de la red local, causando problemas de enrutamiento y conectividad." },
  { id: 99, curso: "CCNA M3", pregunta: "¿Cómo diagnosticarías pérdida de conectividad entre dos routers?", opciones: ["Usando ping para verificar reachability y traceroute para identificar dónde se pierde el tráfico.", "Solo revisando el estado físico de los cables.", "Reiniciando ambos routers.", "Cambiando las direcciones IP.", "Desactivando el firewall."], respuestaCorrecta: 0, explicacion: "ping verifica si hay conectividad básica, y traceroute muestra cada salto intermedio, permitiendo identificar exactamente dónde se pierde la conectividad." },
  { id: 100, curso: "CCNA M3", pregunta: "¿Qué comandos usarías para revisar la tabla de rutas y la conectividad entre saltos?", opciones: ["show ip route y traceroute <destino>", "show interfaces y ping", "show ip ospf y show ip bgp", "debug ip routing y show running-config", "show version y show clock"], respuestaCorrecta: 0, explicacion: "show ip route muestra la tabla de enrutamiento completa, y traceroute permite verificar la ruta que toman los paquetes hacia un destino específico." },
  { id: 101, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué diferencia hay entre una etiqueta de bloque y una en línea?", opciones: ["Las de bloque ocupan todo el ancho disponible y pueden contener otras etiquetas, las en línea solo ocupan el espacio de su contenido.", "No hay diferencia, son intercambiables.", "Las en línea son más modernas que las de bloque.", "Las de bloque solo funcionan con CSS.", "Las en línea no pueden tener estilos."], respuestaCorrecta: 0, explicacion: "Las etiquetas de bloque (div, p, h1) generan un salto de línea y ocupan todo el ancho, mientras que las en línea (span, a, strong) fluyen con el texto y solo ocupan el espacio necesario." },
  { id: 102, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Por qué conviene usar etiquetas semánticas en lugar de solo div?", opciones: ["Mejoran la accesibilidad, SEO y hacen el código más legible y mantenible.", "Son más rápidas de renderizar.", "No requieren CSS.", "Son obligatorias en HTML5.", "Funcionan mejor en móviles."], respuestaCorrecta: 0, explicacion: "Las etiquetas semánticas (header, nav, article, footer) dan significado al contenido, ayudando a navegadores, lectores de pantalla y motores de búsqueda a entender la estructura." },
  { id: 103, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué hace la etiqueta <main>?", opciones: ["Define el contenido principal y único de la página, debe ser único en el documento.", "Crea un menú de navegación.", "Define el pie de página.", "Crea un encabezado principal.", "Define contenido lateral."], respuestaCorrecta: 0, explicacion: "La etiqueta <main> representa el contenido dominante del <body>, excluyendo contenido repetitivo como navegación, barras laterales o pies de página." },
  { id: 104, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Cuál es el propósito de <aside>?", opciones: ["Representa contenido relacionado pero separado del contenido principal, como barras laterales.", "Define el contenido principal de la página.", "Crea un enlace externo.", "Define un artículo independiente.", "Crea un formulario."], respuestaCorrecta: 0, explicacion: "<aside> se usa para contenido tangencialmente relacionado con el contenido principal, como barras laterales, publicidad o enlaces relacionados." },
  { id: 105, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué hace el atributo alt cuando la imagen no carga?", opciones: ["Muestra texto alternativo describiendo la imagen para accesibilidad y SEO.", "Oculta la imagen completamente.", "Redimensiona la imagen automáticamente.", "Cambia el formato de la imagen.", "Elimina la imagen del DOM."], respuestaCorrecta: 0, explicacion: "El atributo alt proporciona texto alternativo que se muestra si la imagen no puede cargarse, y es esencial para lectores de pantalla y accesibilidad." },
  { id: 106, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué importancia tiene la accesibilidad en una web moderna?", opciones: ["Permite que personas con discapacidades puedan usar el sitio, cumpliendo estándares legales y éticos.", "Solo es importante para sitios gubernamentales.", "Mejora la velocidad de carga.", "Reduce el tamaño del código.", "Es opcional y no tiene impacto real."], respuestaCorrecta: 0, explicacion: "La accesibilidad web garantiza que todas las personas, incluidas aquellas con discapacidades visuales, auditivas o motoras, puedan percibir, entender y navegar el contenido." },
  { id: 107, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es validación de formularios del lado del cliente?", opciones: ["Verificar los datos del formulario en el navegador antes de enviarlos al servidor usando JavaScript o HTML5.", "Validar datos en la base de datos.", "Verificar datos en el servidor después de recibirlos.", "Comprobar la conexión a internet.", "Validar el formato del HTML."], respuestaCorrecta: 0, explicacion: "La validación del lado del cliente proporciona retroalimentación inmediata al usuario sin necesidad de enviar el formulario, mejorando la experiencia de usuario." },
  { id: 108, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué ventaja tiene validar también del lado del servidor?", opciones: ["Proporciona seguridad real porque el cliente puede desactivar o manipular la validación del navegador.", "Es más rápida que la validación del cliente.", "No requiere código adicional.", "Solo funciona con bases de datos.", "Es opcional si ya se validó del lado del cliente."], respuestaCorrecta: 0, explicacion: "La validación del servidor es esencial porque un usuario malintencionado puede enviar datos directamente al servidor sin pasar por el formulario, omitiendo la validación del cliente." },
  { id: 109, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué hace el atributo required en un input?", opciones: ["Hace que el campo sea obligatorio antes de enviar el formulario.", "Permite solo valores numéricos.", "Limita la longitud del texto.", "Oculta el campo hasta que se complete otro.", "Establece un valor por defecto."], respuestaCorrecta: 0, explicacion: "El atributo required impide que el formulario se envíe si el campo está vacío, mostrando un mensaje de error nativo del navegador." },
  { id: 110, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué diferencia hay entre readonly y disabled?", opciones: ["readonly permite enfocar y copiar el valor, disabled no permite interacción y no se envía el valor.", "Son exactamente lo mismo.", "disabled permite editar, readonly no.", "readonly oculta el campo, disabled lo muestra.", "disabled es solo para botones, readonly para inputs."], respuestaCorrecta: 0, explicacion: "readonly hace que el campo no sea editable pero sí enfocable y su valor se envía, mientras que disabled desactiva completamente el campo y su valor no se envía." },
  { id: 111, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué tipos de input son útiles para correos, fechas y contraseñas?", opciones: ["type='email', type='date', type='password'", "type='text' para todos", "type='mail', type='calendar', type='secret'", "type='string', type='time', type='hidden'", "type='contact', type='day', type='secure'"], respuestaCorrecta: 0, explicacion: "HTML5 introdujo tipos específicos: email valida formato de correo, date muestra selector de fecha, y password oculta los caracteres ingresados." },
  { id: 112, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué diferencia hay entre GET y POST en envío de formularios?", opciones: ["GET envía datos en la URL (visible y limitado), POST los envía en el cuerpo de la petición (oculto y sin límite práctico).", "GET es más seguro que POST.", "POST solo funciona con bases de datos.", "GET no puede enviar archivos.", "POST es más rápido siempre."], respuestaCorrecta: 0, explicacion: "GET añade los datos como parámetros en la URL (visible en historial, limitado a ~2000 caracteres), POST los envía en el cuerpo HTTP, siendo más seguro para datos sensibles." },
  { id: 113, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Cuándo conviene usar POST en lugar de GET?", opciones: ["Cuando se envían datos sensibles, se modifican datos en el servidor, o se suben archivos.", "Siempre, porque es más rápido.", "Solo para formularios de contacto.", "Nunca, GET es siempre mejor.", "Solo cuando se usa JavaScript."], respuestaCorrecta: 0, explicacion: "POST debe usarse para operaciones que modifican datos, envían información sensible (contraseñas), o manejan grandes cantidades de datos o archivos." },
  { id: 114, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué son los eventos en JavaScript?", opciones: ["Acciones o sucesos que ocurren en el navegador (clic, carga, teclado) que pueden ser detectados y manejados.", "Errores de sintaxis en el código.", "Variables globales del sistema.", "Funciones matemáticas.", "Tipos de datos especiales."], respuestaCorrecta: 0, explicacion: "Los eventos son señales que el navegador dispara cuando algo sucede (usuario hace clic, página carga, tecla se presiona), permitiendo ejecutar código en respuesta." },
  { id: 115, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué diferencia hay entre onclick y addEventListener?", opciones: ["onclick es un atributo HTML que solo permite un handler, addEventListener permite múltiples handlers y más control.", "Son exactamente lo mismo.", "addEventListener es más antiguo que onclick.", "onclick funciona solo con botones.", "addEventListener no soporta eventos de teclado."], respuestaCorrecta: 0, explicacion: "onclick como atributo HTML sobrescribe handlers previos, mientras que addEventListener permite añadir múltiples listeners al mismo evento y ofrece opciones como capture." },
  { id: 116, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué hace querySelector()?", opciones: ["Selecciona el primer elemento del DOM que coincida con el selector CSS proporcionado.", "Selecciona todos los elementos que coincidan.", "Crea un nuevo elemento en el DOM.", "Elimina elementos del DOM.", "Modifica el CSS de un elemento."], respuestaCorrecta: 0, explicacion: "querySelector() devuelve el primer elemento que coincide con el selector CSS especificado, permitiendo seleccionar elementos de forma similar a como se hace en CSS." },
  { id: 117, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué diferencia hay entre innerHTML y textContent?", opciones: ["innerHTML interpreta HTML y puede ejecutar scripts, textContent trata todo como texto plano sin interpretar.", "Son exactamente lo mismo.", "textContent es más lento que innerHTML.", "innerHTML solo funciona con divs.", "textContent no puede leer contenido."], respuestaCorrecta: 0, explicacion: "innerHTML parsea y renderiza HTML (puede ser riesgo de XSS), mientras que textContent inserta o lee solo texto plano, siendo más seguro para contenido de usuario." },
  { id: 118, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué riesgos de seguridad tiene usar innerHTML con datos externos?", opciones: ["Puede ejecutar código JavaScript malicioso (XSS) si se inserta contenido no sanitizado.", "Ninguno, es completamente seguro.", "Solo ralentiza la página.", "Puede corromper la base de datos.", "Solo afecta a Internet Explorer."], respuestaCorrecta: 0, explicacion: "innerHTML puede ejecutar scripts si se inserta contenido de fuentes no confiables sin sanitizar, permitiendo ataques de Cross-Site Scripting (XSS)." },
  { id: 119, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es una función flecha en JavaScript?", opciones: ["Una sintaxis más corta para definir funciones que no tiene su propio 'this'.", "Una función que dibuja flechas en pantalla.", "Una función que solo acepta números.", "Una función que se ejecuta automáticamente.", "Una función que retorna siempre true."], respuestaCorrecta: 0, explicacion: "Las funciones flecha (=>) son una sintaxis concisa introducida en ES6, y a diferencia de las funciones tradicionales, no binding propio de 'this', heredándolo del contexto." },
  { id: 120, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué diferencia hay entre función tradicional y función flecha?", opciones: ["La función tradicional tiene su propio 'this', la función flecha hereda 'this' del contexto donde se define.", "No hay diferencia funcional.", "La función flecha es más rápida.", "La función tradicional no puede retornar valores.", "La función flecha solo funciona con arrays."], respuestaCorrecta: 0, explicacion: "La principal diferencia es el manejo de 'this': las funciones tradicionales lo definen según cómo se llaman, las flecha lo heredan léxicamente del contexto circundante." },
  { id: 121, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué son los arreglos de objetos en JavaScript?", opciones: ["Estructuras de datos que contienen múltiples objetos, accesibles por índice.", "Objetos que solo contienen números.", "Funciones que retornan arrays.", "Variables que almacenan texto.", "Elementos HTML en JavaScript."], respuestaCorrecta: 0, explicacion: "Un arreglo de objetos es una lista donde cada elemento es un objeto, permitiendo almacenar y manipular colecciones de datos estructurados." },
  { id: 122, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué hace el método map()?", opciones: ["Crea un nuevo array con los resultados de aplicar una función a cada elemento del array original.", "Modifica el array original directamente.", "Filtra elementos según una condición.", "Ordena los elementos alfabéticamente.", "Elimina elementos duplicados."], respuestaCorrecta: 0, explicacion: "map() itera sobre cada elemento del array, aplica la función proporcionada y retorna un nuevo array con los resultados, sin modificar el original." },
  { id: 123, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué hace el método filter()?", opciones: ["Crea un nuevo array con solo los elementos que cumplen una condición específica.", "Elimina todos los elementos del array.", "Ordena los elementos.", "Modifica cada elemento del array.", "Combina dos arrays en uno."], respuestaCorrecta: 0, explicacion: "filter() itera sobre el array y retorna un nuevo array containing solo los elementos para los cuales la función de prueba retorna true." },
  { id: 124, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué hace el método reduce()?", opciones: ["Reduce todos los elementos del array a un único valor aplicando una función acumulativa.", "Elimina elementos duplicados.", "Reduce el tamaño del array a la mitad.", "Ordena los elementos de mayor a menor.", "Filtra elementos nulos."], respuestaCorrecta: 0, explicacion: "reduce() aplica una función acumuladora contra un acumulador y cada valor del array (de izquierda a derecha) para reducirlo a un único valor final." },
  { id: 125, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Cuándo conviene usar forEach()?", opciones: ["Cuando necesitas ejecutar una función por cada elemento del array sin necesidad de retornar un nuevo array.", "Cuando necesitas transformar los datos.", "Cuando necesitas filtrar elementos.", "Cuando necesitas ordenar el array.", "Cuando necesitas reducir el array a un valor."], respuestaCorrecta: 0, explicacion: "forEach() ejecuta una función por cada elemento pero no retorna nada (undefined), siendo útil cuando solo necesitas efectos secundarios sin crear un nuevo array." },
  { id: 126, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es una promesa en JavaScript?", opciones: ["Un objeto que representa la eventual finalización (o falla) de una operación asíncrona.", "Una función que se ejecuta inmediatamente.", "Un tipo de variable global.", "Un método para sincronizar hilos.", "Un error de JavaScript."], respuestaCorrecta: 0, explicacion: "Una Promise es un objeto que representa un valor futuro, permitiendo manejar operaciones asíncronas de forma más limpia que los callbacks anidados." },
  { id: 127, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué problema resuelve async/await?", opciones: ["Permite escribir código asíncrono que parece síncrono, mejorando la legibilidad sobre promesas encadenadas.", "Elimina la necesidad de funciones.", "Hace que el código sea más rápido.", "Permite ejecutar código en paralelo real.", "Elimina todos los errores de JavaScript."], respuestaCorrecta: 0, explicacion: "async/await es azúcar sintáctica sobre promesas que permite escribir código asíncrono con una estructura más lineal y legible, evitando el 'callback hell'." },
  { id: 128, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es una API REST?", opciones: ["Una interfaz de programación de aplicaciones que sigue los principios de REST, usando HTTP y formatos como JSON.", "Un lenguaje de programación.", "Una base de datos.", "Un framework de JavaScript.", "Un tipo de servidor web."], respuestaCorrecta: 0, explicacion: "REST (Representational State Transfer) es un estilo arquitectónico para APIs que usa métodos HTTP (GET, POST, PUT, DELETE) y típicamente JSON para intercambio de datos." },
  { id: 129, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué representa el código HTTP 200?", opciones: ["Éxito: la petición fue recibida, entendida y aceptada correctamente.", "Error del servidor.", "Recurso no encontrado.", "Redirección a otra página.", "Petición no autorizada."], respuestaCorrecta: 0, explicacion: "200 OK es el código de estado estándar indicando que la petición HTTP se completó con éxito y la respuesta contiene el recurso solicitado." },
  { id: 130, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué significa una respuesta HTTP 404?", opciones: ["El recurso solicitado no fue encontrado en el servidor.", "Error interno del servidor.", "Petición exitosa.", "Redirección permanente.", "Autenticación requerida."], respuestaCorrecta: 0, explicacion: "404 Not Found indica que el servidor pudo procesar la petición pero no puede encontrar el recurso solicitado (URL incorrecta o recurso eliminado)." },
  { id: 131, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué indica un error 500?", opciones: ["Error interno del servidor: el servidor encontró una condición inesperada que le impidió completar la petición.", "Recurso no encontrado.", "Petición exitosa.", "Redirección temporal.", "Falta de permisos."], respuestaCorrecta: 0, explicacion: "500 Internal Server Error es un código genérico indicando que el servidor encontró un error (bug, excepción, configuración incorrecta) sin más detalles específicos." },
  { id: 132, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué hace una regla CSS de especificidad?", opciones: ["Determina qué estilos se aplican cuando múltiples reglas compiten por el mismo elemento.", "Aumenta la velocidad de carga del CSS.", "Comprime el código CSS.", "Valida la sintaxis CSS.", "Crea animaciones automáticamente."], respuestaCorrecta: 0, explicacion: "La especificidad es el sistema de pesos que CSS usa para decidir qué declaración se aplica cuando hay conflictos: inline > ID > clase > elemento." },
  { id: 133, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué diferencia hay entre padding y margin?", opciones: ["padding es el espacio interno entre el contenido y el borde, margin es el espacio externo fuera del borde.", "Son exactamente lo mismo.", "margin es interno, padding es externo.", "padding solo funciona con imágenes.", "margin no se puede cambiar con CSS."], respuestaCorrecta: 0, explicacion: "padding crea espacio dentro del elemento (entre contenido y borde), margin crea espacio fuera del elemento (entre elementos vecinos)." },
  { id: 134, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Cómo funciona position: relative?", opciones: ["Posiciona el elemento relativo a su posición normal en el flujo del documento, sin afectar a otros elementos.", "Lo posiciona relativo al viewport.", "Lo posiciona relativo al padre más cercano con posición.", "Lo fija en la pantalla.", "Lo elimina del flujo del documento."], respuestaCorrecta: 0, explicacion: "position: relative mueve el elemento desde su posición original en el flujo normal, pero el espacio que ocupaba originalmente se mantiene reservado." },
  { id: 135, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué diferencia hay entre absolute, fixed y sticky?", opciones: ["absolute se posiciona respecto al padre posicionado más cercano, fixed respecto al viewport, sticky alterna entre ambos según el scroll.", "Son exactamente lo mismo.", "fixed es más moderno que absolute.", "sticky solo funciona en móviles.", "absolute no permite top/left."], respuestaCorrecta: 0, explicacion: "absolute se posiciona respecto al ancestro posicionado más cercano, fixed siempre respecto al viewport (no se mueve con scroll), sticky se comporta como relative hasta cierto punto del scroll." },
  { id: 136, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es z-index y cuándo se usa?", opciones: ["Controla el orden de apilamiento de elementos posicionados, valores mayores aparecen encima.", "Mide la profundidad de color.", "Controla el zoom del elemento.", "Define la transparencia.", "Establece el tamaño del borde."], respuestaCorrecta: 0, explicacion: "z-index determina qué elemento aparece encima cuando se superponen, solo funciona en elementos con position diferente a static." },
  { id: 137, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué hace box-sizing: border-box?", opciones: ["Incluye padding y borde en el ancho/alto total del elemento, facilitando el cálculo de dimensiones.", "Excluye padding y borde del ancho total.", "Elimina todos los bordes.", "Centra el elemento automáticamente.", "Añade sombras al borde."], respuestaCorrecta: 0, explicacion: "Con border-box, si defines width: 100px, el elemento será 100px incluyendo padding y borde, no sumándolos, haciendo más predecible el diseño." },
  { id: 138, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué ventaja tiene usar Flexbox en vez de posicionamiento manual?", opciones: ["Permite alinear y distribuir elementos de forma flexible y responsiva sin calcular posiciones manualmente.", "Es más antiguo y compatible.", "No requiere CSS.", "Solo funciona con imágenes.", "Es más lento que position absolute."], respuestaCorrecta: 0, explicacion: "Flexbox proporciona un modelo de layout unidimensional que facilita la alineación, distribución y reordenamiento de elementos, adaptándose automáticamente al espacio disponible." },
  { id: 139, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué resuelve CSS Grid mejor que Flexbox?", opciones: ["Layouts bidimensionales complejos con control preciso de filas y columnas simultáneamente.", "Flexbox es mejor en todo.", "Grid solo funciona con imágenes.", "Grid no es responsivo.", "Grid requiere más código siempre."], respuestaCorrecta: 0, explicacion: "CSS Grid es un sistema bidimensional que permite controlar filas y columnas simultáneamente, ideal para layouts complejos, mientras Flexbox es unidimensional." },
  { id: 140, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué son los breakpoints en diseño responsivo?", opciones: ["Puntos específicos donde el diseño cambia usando media queries para adaptarse a diferentes tamaños de pantalla.", "Errores en el CSS.", "Límites de tamaño de imagen.", "Puntos de ruptura del servidor.", "Marcadores de posición."], respuestaCorrecta: 0, explicacion: "Los breakpoints definen en qué anchos de pantalla el diseño debe reorganizarse, permitiendo crear experiencias optimizadas para móviles, tablets y escritorio." },
  { id: 141, curso: "Algoritmia", pregunta: "¿Cómo determinarías si un algoritmo está bien optimizado?", opciones: ["Analizando su complejidad temporal y espacial, y comparándola con alternativas para el mismo problema.", "Solo midiendo el tiempo de ejecución en una computadora.", "Contando las líneas de código.", "Verificando si usa las últimas tecnologías.", "Comprobando si tiene muchos comentarios."], respuestaCorrecta: 0, explicacion: "La optimización se evalúa mediante análisis de complejidad (notación O grande) considerando tiempo y espacio, no solo por ejecución empírica que depende del hardware." },
  { id: 142, curso: "Algoritmia", pregunta: "¿Qué diferencia hay entre iteración y recursión?", opciones: ["Iteración usa bucles para repetir código, recursión usa funciones que se llaman a sí mismas.", "Son exactamente lo mismo.", "Recursión es siempre más rápida.", "Iteración no puede resolver problemas complejos.", "Recursión no usa memoria."], respuestaCorrecta: 0, explicacion: "La iteración repite un bloque de código usando estructuras como for/while, la recursión resuelve problemas dividiéndolos en subproblemas más pequeños mediante llamadas a la misma función." },
  { id: 143, curso: "Algoritmia", pregunta: "¿Cuándo conviene usar recursión?", opciones: ["Cuando el problema tiene estructura recursiva natural (árboles, factorial, Fibonacci) y la solución recursiva es más clara.", "Siempre, porque es más elegante.", "Nunca, siempre es mejor iteración.", "Solo en lenguajes funcionales.", "Cuando se necesita máximo rendimiento."], respuestaCorrecta: 0, explicacion: "La recursión es ideal para problemas que pueden dividirse en subproblemas similares (divide y vencerás), estructuras recursivas como árboles, o cuando la solución recursiva es más legible." },
  { id: 144, curso: "Algoritmia", pregunta: "¿Cuál es el riesgo de una recursión mal planteada?", opciones: ["Puede causar desbordamiento de pila (stack overflow) por demasiadas llamadas anidadas o no tener caso base.", "No hay riesgos, es completamente segura.", "Solo consume más tiempo.", "Hace que el código sea más largo.", "Corrompe la memoria permanentemente."], respuestaCorrecta: 0, explicacion: "Sin caso base o con profundidad excesiva, cada llamada recursiva añade un marco a la pila de llamadas, eventualmente agotando la memoria disponible y causando stack overflow." },
  { id: 145, curso: "Algoritmia", pregunta: "¿Qué es el caso base en una función recursiva?", opciones: ["La condición que detiene la recursión, evitando llamadas infinitas.", "El primer parámetro de la función.", "El valor de retorno siempre.", "Una variable global.", "El nombre de la función."], respuestaCorrecta: 0, explicacion: "El caso base es la condición terminal que permite a la función retornar un valor sin hacer más llamadas recursivas, siendo esencial para evitar recursión infinita." },
  { id: 146, curso: "Algoritmia", pregunta: "¿Cómo analizarías la complejidad de un ciclo anidado?", opciones: ["Multiplicando la complejidad del ciclo externo por la del interno, considerando el número de iteraciones de cada uno.", "Sumando las complejidades de ambos ciclos.", "Solo contando el ciclo más grande.", "Ignorando el ciclo interno.", "Dividiendo el total de iteraciones entre 2."], respuestaCorrecta: 0, explicacion: "Para ciclos anidados, la complejidad total es el producto de las iteraciones: si el externo ejecuta N veces y el interno M veces por cada iteración externa, la complejidad es O(N*M)." },
  { id: 147, curso: "Algoritmia", pregunta: "¿Qué complejidad suele tener un doble for sobre una matriz?", opciones: ["O(n²) donde n es el tamaño de la matriz, porque cada elemento se visita una vez por cada fila y columna.", "O(n)", "O(log n)", "O(1)", "O(n log n)"], respuestaCorrecta: 0, explicacion: "Un doble for que itera sobre todos los elementos de una matriz n×n tiene complejidad cuadrática O(n²) porque hay n² iteraciones totales." },
  { id: 148, curso: "Algoritmia", pregunta: "¿Qué diferencia hay entre mejor caso, peor caso y caso promedio?", opciones: ["Mejor caso es la entrada más favorable, peor caso la menos favorable, caso promedio el comportamiento típico con entradas aleatorias.", "Son lo mismo, solo cambia el nombre.", "El peor caso nunca ocurre en la práctica.", "El mejor caso es el más importante siempre.", "El caso promedio es imposible de calcular."], respuestaCorrecta: 0, explicacion: "El análisis de casos estudia el rendimiento del algoritmo bajo diferentes escenarios: mejor (entrada óptima), peor (entrada más desfavorable) y promedio (comportamiento esperado)." },
  { id: 149, curso: "Algoritmia", pregunta: "¿Qué es un algoritmo voraz?", opciones: ["Un algoritmo que toma la decisión óptima local en cada paso esperando alcanzar una solución global óptima.", "Un algoritmo que prueba todas las combinaciones posibles.", "Un algoritmo que usa recursión siempre.", "Un algoritmo que ordena datos.", "Un algoritmo que busca en grafos."], respuestaCorrecta: 0, explicacion: "Los algoritmos voraces (greedy) hacen la elección que parece mejor en el momento actual, sin reconsiderar decisiones previas, funcionando óptimamente para ciertos problemas." },
  { id: 150, curso: "Algoritmia", pregunta: "¿En qué tipo de problemas suele funcionar bien un enfoque voraz?", opciones: ["Problemas con propiedad de subestructura óptima y elección voraz, como el problema del cambio de monedas o árbol de expansión mínima.", "Problemas NP-completos.", "Problemas que requieren backtracking.", "Problemas de ordenamiento únicamente.", "Problemas con soluciones múltiples igualmente válidas."], respuestaCorrecta: 0, explicacion: "Los algoritmos voraces funcionan cuando la solución óptima global puede alcanzarse mediante elecciones óptimas locales, como en Kruskal, Prim, Dijkstra o el problema de la mochila fraccional." },
  { id: 151, curso: "Algoritmia", pregunta: "¿Qué es programación dinámica?", opciones: ["Una técnica que resuelve problemas complejos dividiéndolos en subproblemas más simples y almacenando sus resultados para evitar recalcularlos.", "Programación orientada a objetos.", "Programación en tiempo real.", "Programación de videojuegos.", "Programación sin variables."], respuestaCorrecta: 0, explicacion: "La programación dinámica resuelve problemas con subestructura óptima y subproblemas superpuestos, almacenando resultados intermedios (memoización o tabulación) para evitar trabajo redundante." },
  { id: 152, curso: "Algoritmia", pregunta: "¿Qué ventaja tiene programación dinámica frente a la fuerza bruta?", opciones: ["Reduce drásticamente la complejidad temporal al evitar recalcular subproblemas ya resueltos.", "Usa menos memoria siempre.", "Es más fácil de implementar.", "Funciona con todos los problemas.", "No tiene ventaja, son equivalentes."], respuestaCorrecta: 0, explicacion: "Mientras fuerza bruta explora todas las posibilidades (exponencial en muchos casos), programación dinámica almacena resultados intermedios, reduciendo complejidad exponencial a polinomial." },
  { id: 153, curso: "Algoritmia", pregunta: "¿Qué es memoización?", opciones: ["Una técnica de optimización que almacena resultados de llamadas a función costosas para retornarlos cuando se llame con los mismos parámetros.", "Memorizar código de memoria.", "Un tipo de bucle optimizado.", "Una forma de compresión de datos.", "Un método de ordenamiento."], respuestaCorrecta: 0, explicacion: "Memoización es una técnica top-down que cachea resultados de funciones, verificando primero si el resultado ya fue calculado antes de realizar el cálculo nuevamente." },
  { id: 154, curso: "Algoritmia", pregunta: "¿Qué es una pila de llamadas?", opciones: ["Una estructura de datos que registra las llamadas a función activas, almacenando variables locales y dirección de retorno.", "Una lista de tareas pendientes.", "Un tipo de array especial.", "Una cola de procesos.", "Un sistema de archivos."], respuestaCorrecta: 0, explicacion: "La pila de llamadas (call stack) es una estructura LIFO que rastrea las funciones activas, almacenando para cada llamada: parámetros, variables locales y dónde continuar al retornar." },
  { id: 155, curso: "Algoritmia", pregunta: "¿Qué ocurre si una función recursiva no tiene caso base?", opciones: ["Se ejecuta infinitamente hasta agotar la pila de llamadas y causar un stack overflow.", "Se ejecuta una sola vez.", "Retorna null automáticamente.", "El compilador lo detecta y lo corrige.", "Funciona normalmente pero más lento."], respuestaCorrecta: 0, explicacion: "Sin caso base, la función se llama a sí misma indefinidamente, cada llamada consume memoria en la pila hasta que se desborda, terminando el programa con error." },
  { id: 156, curso: "Algoritmia", pregunta: "¿Cómo funciona una búsqueda binaria paso a paso?", opciones: ["Divide repetidamente el array ordenado a la mitad, comparando el elemento medio con el objetivo y descartando la mitad donde no puede estar.", "Revisa cada elemento secuencialmente.", "Ordena el array primero y luego busca.", "Usa hash tables para encontrar el elemento.", "Compara con el primer y último elemento solamente."], respuestaCorrecta: 0, explicacion: "Búsqueda binaria requiere array ordenado: compara con el elemento medio, si es menor busca en la mitad izquierda, si es mayor en la derecha, repitiendo hasta encontrar o agotar el rango." },
  { id: 157, curso: "Algoritmia", pregunta: "¿Qué complejidad tiene una búsqueda binaria en el peor caso?", opciones: ["O(log n) porque en cada paso se reduce el espacio de búsqueda a la mitad.", "O(n)", "O(n²)", "O(1)", "O(n log n)"], respuestaCorrecta: 0, explicacion: "En el peor caso, búsqueda binaria realiza log₂(n) comparaciones porque el tamaño del problema se reduce a la mitad en cada iteración, siendo mucho más eficiente que búsqueda lineal O(n)." },
  { id: 158, curso: "Algoritmia", pregunta: "¿Qué diferencia hay entre ordenamiento estable e inestable?", opciones: ["Un ordenamiento estable mantiene el orden relativo de elementos con claves iguales, inestable no lo garantiza.", "Estable es más rápido.", "Inestable usa menos memoria.", "Estable solo funciona con números.", "Inestable no puede ordenar strings."], respuestaCorrecta: 0, explicacion: "La estabilidad en ordenamiento preserva el orden original de elementos equivalentes: si A y B tienen la misma clave y A estaba antes, en un ordenamiento estable A seguirá antes que B." },
  { id: 159, curso: "Algoritmia", pregunta: "¿Por qué el ordenamiento por inserción puede ser eficiente en listas pequeñas?", opciones: ["Tiene baja sobrecarga y es adaptativo, funcionando bien en listas pequeñas o casi ordenadas con O(n) en mejor caso.", "Es el algoritmo más rápido siempre.", "Usa programación dinámica.", "No requiere comparaciones.", "Funciona en tiempo constante O(1)."], respuestaCorrecta: 0, explicacion: "Inserción tiene complejidad O(n²) en promedio pero O(n) en listas casi ordenadas, con baja constante y buen rendimiento en listas pequeñas, siendo usado como base de algoritmos más complejos." },
  { id: 160, curso: "Algoritmia", pregunta: "¿Cómo compararías la eficiencia de dos algoritmos que resuelven lo mismo?", opciones: ["Analizando su complejidad temporal y espacial en notación O grande, considerando mejor, peor y caso promedio.", "Solo midiendo el tiempo de ejecución una vez.", "Contando líneas de código.", "Viendo cuál usa menos variables.", "Comparando el tamaño del código fuente."], respuestaCorrecta: 0, explicacion: "La comparación rigurosa requiere análisis asintótico (notación O grande) considerando tiempo y espacio en diferentes escenarios, no solo mediciones empíricas que dependen del hardware." },
  { id: 161, curso: "CCNA M1 y M2", pregunta: "¿Cómo diferenciarías una red pública de una red privada?", opciones: ["Las redes privadas usan rangos IP reservados (10.x.x.x, 172.16-31.x.x, 192.168.x.x) y no son enrutables en Internet.", "Las redes públicas son más rápidas.", "Las redes privadas no tienen seguridad.", "Las redes públicas solo usan IPv6.", "No hay diferencia técnica."], respuestaCorrecta: 0, explicacion: "Las IPs privadas (RFC 1918) son reservadas para uso interno y no pueden enrutarse en Internet, mientras que las IPs públicas son únicas globalmente y enrutables en Internet." },
  { id: 162, curso: "CCNA M1 y M2", pregunta: "¿Qué efecto tiene NAT en la comunicación entre redes?", opciones: ["Traduce direcciones IP privadas a públicas permitiendo que múltiples dispositivos compartan una IP pública para salir a Internet.", "Aumenta la velocidad de la red.", "Elimina la necesidad de routers.", "Cifra todo el tráfico automáticamente.", "Convierte IPv4 a IPv6."], respuestaCorrecta: 0, explicacion: "NAT (Network Address Translation) permite que dispositivos con IPs privadas se comuniquen con Internet traduciendo sus direcciones a una o pocas IPs públicas en el router frontera." },
  { id: 163, curso: "CCNA M1 y M2", pregunta: "¿Qué problema resuelve la traducción de direcciones?", opciones: ["Permite que muchos dispositivos con IPs privadas compartan pocas IPs públicas, mitigando el agotamiento de IPv4.", "Aumenta el ancho de banda.", "Mejora la seguridad física.", "Elimina la necesidad de DNS.", "Acelera la convergencia de OSPF."], respuestaCorrecta: 0, explicacion: "NAT fue creado para extender la vida útil de IPv4 permitiendo que redes enteras usen direcciones privadas y compartan una o pocas direcciones públicas para acceso a Internet." },
  { id: 164, curso: "CCNA M1 y M2", pregunta: "¿Qué diferencia hay entre una dirección IP estática y una obtenida por DHCP?", opciones: ["Estática se configura manualmente y no cambia, DHCP la asigna automáticamente un servidor y puede cambiar.", "DHCP es más segura que estática.", "Estática solo funciona con IPv6.", "DHCP no permite acceso a Internet.", "Estática es más rápida siempre."], respuestaCorrecta: 0, explicacion: "IP estática se configura manualmente en el dispositivo y permanece fija, mientras que DHCP (Dynamic Host Configuration Protocol) asigna IPs dinámicamente desde un pool, pudiendo cambiar." },
  { id: 165, curso: "CCNA M1 y M2", pregunta: "¿Qué información entrega un ping exitoso y qué no garantiza?", opciones: ["Confirma reachability y tiempo de respuesta, pero no garantiza que todos los servicios o puertos estén funcionando.", "Garantiza que la aplicación web funciona.", "Confirma que no hay firewall.", "Garantiza ancho de banda suficiente.", "Confirma que DNS funciona correctamente."], respuestaCorrecta: 0, explicacion: "ping verifica conectividad ICMP a nivel de red, confirmando que el host responde, pero no prueba servicios específicos (HTTP, FTP), firewalls pueden bloquear ICMP, ni garantiza calidad del enlace." },
  { id: 166, curso: "CCNA M1 y M2", pregunta: "¿Qué utilidad tiene tracert o traceroute al diagnosticar fallas?", opciones: ["Muestra cada salto (router) que atraviesan los paquetes hacia el destino, identificando dónde se pierde conectividad o hay latencia.", "Solo muestra si el destino existe.", "Mide el ancho de banda disponible.", "Cifra la comunicación.", "Configura rutas estáticas."], respuestaCorrecta: 0, explicacion: "traceroute usa TTL incremental para descubrir cada router en la ruta al destino, mostrando dirección IP, tiempo de respuesta por salto, permitiendo identificar problemas de conectividad o congestión." },
  { id: 167, curso: "CCNA M1 y M2", pregunta: "¿Por qué un switch aprende direcciones MAC?", opciones: ["Para construir una tabla de direcciones MAC-puerto y reenviar tramas solo al puerto correcto en lugar de hacer flood a todos.", "Para asignar direcciones IP.", "Para filtrar tráfico por protocolo.", "Para detectar intrusos en la red.", "Para cifrar las comunicaciones."], respuestaCorrecta: 0, explicacion: "Los switch aprenden qué dirección MAC está conectada a cada puerto examinando la MAC de origen de las tramas recibidas, construyendo una tabla para reenvío eficiente." },
  { id: 168, curso: "CCNA M1 y M2", pregunta: "¿Qué sucede cuando una tabla MAC envejece?", opciones: ["Las entradas que no se refrescan se eliminan después de un tiempo (aging time), evitando entradas obsoletas.", "La tabla se llena y el switch deja de funcionar.", "Las entradas se vuelven permanentes.", "El switch reinicia automáticamente.", "Se duplican las entradas."], respuestaCorrecta: 0, explicacion: "Las entradas de la tabla MAC tienen un tiempo de vida (aging time, típicamente 300 segundos), si no se ven tramas de esa MAC en ese tiempo, la entrada se elimina para mantener la tabla actualizada." },
  { id: 169, curso: "CCNA M1 y M2", pregunta: "¿Qué riesgo existe si hay una VLAN mal asignada?", opciones: ["Puede causar problemas de conectividad, violaciones de seguridad o tráfico de una VLAN filtrándose a otra.", "No hay riesgos, es solo configuración.", "Solo afecta la velocidad.", "El switch se daña físicamente.", "Se borra la configuración completa."], respuestaCorrecta: 0, explicacion: "VLANs mal configuradas pueden permitir que tráfico sensible llegue a segmentos no autorizados, causar islas de conectividad, o violar políticas de seguridad y segmentación de red." },
  { id: 170, curso: "CCNA M1 y M2", pregunta: "¿Qué diferencia hay entre un puerto trunk y uno access en una red con varias VLAN?", opciones: ["Access pertenece a una sola VLAN, trunk transporta tráfico de múltiples VLANs usando tags 802.1Q.", "Son exactamente lo mismo.", "Trunk es más rápido que access.", "Access solo funciona con routers.", "Trunk no puede transportar datos."], respuestaCorrecta: 0, explicacion: "Un puerto access pertenece a una VLAN específica y no etiqueta tramas, un trunk transporta tráfico de múltiples VLANs entre switches o routers, etiquetando con 802.1Q para identificar cada VLAN." },
  { id: 171, curso: "CCNA M1 y M2", pregunta: "¿Qué ocurre si la VLAN nativa no coincide en dos switches conectados?", opciones: ["Puede causar fugas de tráfico entre VLANs y problemas de seguridad porque tramas sin tag se mezclan en VLANs diferentes.", "No hay ningún problema.", "El trunk no funciona en absoluto.", "Los switches se reinician.", "Se desactiva STP."], respuestaCorrecta: 0, explicacion: "Si la VLAN nativa no coincide en un enlace trunk, las tramas sin etiqueta de un switch se asignarán a una VLAN diferente en el otro switch, causando fugas de tráfico y problemas de seguridad." },
  { id: 172, curso: "CCNA M1 y M2", pregunta: "¿Qué es un broadcast y cómo se comporta en una VLAN?", opciones: ["Una trama enviada a todos los dispositivos de la VLAN, los switches la inundan a todos los puertos de esa VLAN excepto el origen.", "Un mensaje privado entre dos dispositivos.", "Un tipo de enrutamiento.", "Una trama multicast especial.", "Un protocolo de seguridad."], respuestaCorrecta: 0, explicacion: "Broadcast (MAC FF:FF:FF:FF:FF:FF) se envía a todos los dispositivos. Los switches limitan el dominio de broadcast inundando solo dentro de la VLAN, no a otras VLANs." },
  { id: 173, curso: "CCNA M1 y M2", pregunta: "¿Qué papel cumple el gateway en la comunicación entre subredes?", opciones: ["Actúa como punto de salida de la subred local, enrutando tráfico hacia otras subredes o Internet.", "Asigna direcciones IP automáticamente.", "Filtra tráfico por MAC.", "Cifra las comunicaciones entre subredes.", "Sincroniza relojes entre subredes."], respuestaCorrecta: 0, explicacion: "El gateway (típicamente la interfaz del router en la subred) es el destino para tráfico que no pertenece a la subred local, encargándose de enrutar paquetes hacia su destino final." },
  { id: 174, curso: "CCNA M1 y M2", pregunta: "¿Qué significa que dos equipos estén en la misma subred?", opciones: ["Tienen IPs en el mismo rango de red según su máscara, pudiendo comunicarse directamente sin router.", "Están conectados al mismo switch físicamente.", "Tienen la misma dirección IP.", "Usan el mismo sistema operativo.", "Están en la misma VLAN siempre."], respuestaCorrecta: 0, explicacion: "Dos hosts están en la misma subred si al aplicar la máscara de subred a sus IPs obtienen la misma dirección de red, permitiendo comunicación directa capa 2 sin necesidad de enrutamiento." },
  { id: 175, curso: "CCNA M1 y M2", pregunta: "¿Cómo identificarías si un problema es de capa 2 o capa 3?", opciones: ["Si puedes hacer ping al gateway pero no más allá, es capa 3; si no puedes hacer ping ni al gateway, es capa 2.", "No se puede diferenciar.", "Siempre es capa 2 primero.", "Capa 3 solo afecta a WiFi.", "Capa 2 solo afecta a fibra óptica."], respuestaCorrecta: 0, explicacion: "Si la conectividad capa 2 funciona (mismo VLAN, enlace up) pero no hay reachability capa 3, el problema es de enrutamiento; si ni siquiera hay enlace o VLAN correcta, es problema capa 2." },
  { id: 176, curso: "CCNA M1 y M2", pregunta: "¿Qué diferencia existe entre una dirección unicast, multicast y broadcast?", opciones: ["Unicast es uno-a-uno, multicast es uno-a-muchos específicos, broadcast es uno-a-todos en la subred.", "Son lo mismo con diferentes nombres.", "Multicast solo funciona con video.", "Broadcast es más eficiente que unicast.", "Unicast no usa direcciones IP."], respuestaCorrecta: 0, explicacion: "Unicast envía a un solo destino, multicast a un grupo de interesados (rango 224.0.0.0/4), broadcast a todos los hosts de la subred (dirección de broadcast)." },
  { id: 177, curso: "CCNA M1 y M2", pregunta: "¿Por qué una mala máscara de subred puede cortar conectividad?", opciones: ["Porque hace que el host calcule incorrectamente qué direcciones están en su subred local y cuáles requieren gateway.", "No afecta la conectividad.", "Solo ralentiza la red.", "Causa errores físicos en el cable.", "Desactiva el switch."], respuestaCorrecta: 0, explicacion: "Con una máscara incorrecta, el host puede pensar que un destino está en la subred local (enviando directo) cuando requiere gateway, o viceversa, causando fallos de comunicación." },
  { id: 178, curso: "CCNA M1 y M2", pregunta: "¿Qué relación hay entre IP, máscara y gateway?", opciones: ["La IP identifica el host, la máscara define la subred, el gateway es la puerta de salida hacia otras redes.", "Son independientes y no se relacionan.", "La máscara reemplaza a la IP.", "El gateway asigna la máscara.", "La IP determina el gateway automáticamente."], respuestaCorrecta: 0, explicacion: "La IP identifica unívocamente el dispositivo, la máscara define qué porción de la IP es red y qué es host, el gateway es la IP del router que permite salir de la subred local." },
  { id: 179, curso: "CCNA M1 y M2", pregunta: "¿Qué comandos usarías para revisar estado de interfaces en un switch o router?", opciones: ["show ip interface brief, show interfaces, show running-config interface <nombre>", "display all interfaces", "list ports status", "check network health", "view connections active"], respuestaCorrecta: 0, explicacion: "show ip interface brief muestra estado resumido (up/down, IP), show interfaces da detalles completos (estadísticas, errores), show running-config muestra la configuración de la interfaz." },
  { id: 180, curso: "CCNA M1 y M2", pregunta: "¿Qué puede indicar una interfaz en estado down/down?", opciones: ["Problema físico: cable desconectado, dispositivo remoto apagado, o interfaz administrativamente shut down.", "Problema de configuración IP.", "Problema de enrutamiento.", "La interfaz está funcionando normalmente.", "Problema de VLAN."], respuestaCorrecta: 0, explicacion: "down/down (ambos estados) indica problema de capa 1: no hay enlace físico. Puede ser cable desconectado, dispositivo remoto apagado, o la interfaz está administrativamente desactivada (shutdown)." }
];
export const preguntasNivel2 = preguntasNivel2_Parte1;
